import{_ as a,o as d,c as e,ag as s}from"./chunks/framework.uOkKsJ4G.js";const b=JSON.parse('{"title":"AI 视频解说工作流","description":"深入了解 Narrafiilm AI 第一人称视频解说全流程的工作原理与使用技巧。","frontmatter":{"title":"AI 视频解说工作流","description":"深入了解 Narrafiilm AI 第一人称视频解说全流程的工作原理与使用技巧。"},"headers":[],"relativePath":"guide/ai-video-guide.md","filePath":"guide/ai-video-guide.md","lastUpdated":1775975848000}'),n={name:"guide/ai-video-guide.md"};function i(r,t,l,h,p,o){return d(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="ai-视频解说工作流" tabindex="-1">AI 视频解说工作流 <a class="header-anchor" href="#ai-视频解说工作流" aria-label="Permalink to &quot;AI 视频解说工作流&quot;">​</a></h1><p>本文档详细介绍 Narrafiilm <strong>AI 第一人称视频解说</strong>（MonologueMaker）的工作流程，帮助你理解每个环节的原理，从而更好地掌控输出质量。</p><hr><h2 id="完整工作流" tabindex="-1">完整工作流 <a class="header-anchor" href="#完整工作流" aria-label="Permalink to &quot;完整工作流&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>视频输入</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>场景分析（Qwen2.5-VL）</span></span>
<span class="line"><span>   │  逐帧抽帧 → 主角识别 → 场景分段</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>解说生成（DeepSeek-V3）</span></span>
<span class="line"><span>   │  &quot;我&quot;视角 → 情感风格 → 多版本备选</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>配音合成（Edge-TTS / F5-TTS）</span></span>
<span class="line"><span>   │  文字→语音 → 语速/音调调节</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>字幕对齐（TTS Word-level Timing）</span></span>
<span class="line"><span>   │  ASS 格式 → 逐字同步</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>视频合成（FFmpeg）</span></span>
<span class="line"><span>   │  配音+字幕+原片 → H.264/H.265 编码</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>输出（MP4 / 剪映草稿 JSON）</span></span></code></pre></div><hr><h2 id="step-1-—-场景分析" tabindex="-1">Step 1 — 场景分析 <a class="header-anchor" href="#step-1-—-场景分析" aria-label="Permalink to &quot;Step 1 — 场景分析&quot;">​</a></h2><h3 id="抽帧策略" tabindex="-1">抽帧策略 <a class="header-anchor" href="#抽帧策略" aria-label="Permalink to &quot;抽帧策略&quot;">​</a></h3><p>Narrafiilm 使用 <strong>Qwen2.5-VL（7B）</strong> 逐帧分析视频画面。</p><table tabindex="0"><thead><tr><th>参数</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td>抽帧间隔</td><td>1 秒</td><td>每隔 N 秒取一帧分析</td></tr><tr><td>最小场景长度</td><td>3 秒</td><td>短于此长度的场景合并</td></tr><tr><td>置信度阈值</td><td>0.7</td><td>低于此值忽略该帧</td></tr></tbody></table><h3 id="场景分段算法" tabindex="-1">场景分段算法 <a class="header-anchor" href="#场景分段算法" aria-label="Permalink to &quot;场景分段算法&quot;">​</a></h3><p>基于画面内容变化率（帧间差异）自动切分场景边界，逻辑：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每个场景 = 连续帧间差异 &lt; 阈值的连续片段</span></span></code></pre></div><p>长视频自动分段处理，每段独立分析后合并结果。</p><h3 id="主角识别" tabindex="-1">主角识别 <a class="header-anchor" href="#主角识别" aria-label="Permalink to &quot;主角识别&quot;">​</a></h3><p>AI 识别画面中的主要人物（最大面积 / 中心位置），将其作为&quot;我&quot;的视角来源。识别结果包含：</p><ul><li>主角外貌特征描述</li><li>主角动作与意图</li><li>主角与场景中其他对象的交互关系</li></ul><hr><h2 id="step-2-—-解说生成" tabindex="-1">Step 2 — 解说生成 <a class="header-anchor" href="#step-2-—-解说生成" aria-label="Permalink to &quot;Step 2 — 解说生成&quot;">​</a></h2><h3 id="情感风格选择" tabindex="-1">情感风格选择 <a class="header-anchor" href="#情感风格选择" aria-label="Permalink to &quot;情感风格选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th>风格</th><th>适用内容</th><th>解说语气</th></tr></thead><tbody><tr><td><strong>治愈</strong></td><td>旅行、自然风光、生活记录</td><td>温暖、放松、随性</td></tr><tr><td><strong>悬疑</strong></td><td>惊悚、探秘、推理向内容</td><td>低沉、留白、制造紧张感</td></tr><tr><td><strong>励志</strong></td><td>挑战、成长、努力过程</td><td>坚定、有力、积极</td></tr><tr><td><strong>怀旧</strong></td><td>回忆、老物件、时光流逝</td><td>柔和、感慨、余韵悠长</td></tr><tr><td><strong>浪漫</strong></td><td>情感、约会、美好时刻</td><td>细腻、温柔、充满画面感</td></tr></tbody></table><h3 id="长度控制" tabindex="-1">长度控制 <a class="header-anchor" href="#长度控制" aria-label="Permalink to &quot;长度控制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>每段字数</th><th>适用场景</th></tr></thead><tbody><tr><td>简洁版</td><td>30–60 字</td><td>短视频（&lt;1 分钟）</td></tr><tr><td>标准版</td><td>60–120 字</td><td>3–10 分钟视频</td></tr><tr><td>详细版</td><td>120–200 字</td><td>纪录片风格</td></tr></tbody></table><h3 id="prompt-工程" tabindex="-1">Prompt 工程 <a class="header-anchor" href="#prompt-工程" aria-label="Permalink to &quot;Prompt 工程&quot;">​</a></h3><p>Narrafiilm 内部构建的 Prompt 结构（用户不可见）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是视频中的主角，用&quot;我&quot;的视角描述正在发生的一切。</span></span>
<span class="line"><span>语气：[情感风格]</span></span>
<span class="line"><span>主角特征：[主角外貌描述]</span></span>
<span class="line"><span>场景：[场景描述]</span></span>
<span class="line"><span>要求：</span></span>
<span class="line"><span>- 使用第一人称&quot;我&quot;</span></span>
<span class="line"><span>- 自然流畅，像真实的人在说话</span></span>
<span class="line"><span>- 不重复画面已有信息，而是补充画面背后的情感和想法</span></span>
<span class="line"><span>- [字数要求]</span></span></code></pre></div><hr><h2 id="step-3-—-配音合成" tabindex="-1">Step 3 — 配音合成 <a class="header-anchor" href="#step-3-—-配音合成" aria-label="Permalink to &quot;Step 3 — 配音合成&quot;">​</a></h2><h3 id="edge-tts-默认" tabindex="-1">Edge-TTS（默认） <a class="header-anchor" href="#edge-tts-默认" aria-label="Permalink to &quot;Edge-TTS（默认）&quot;">​</a></h3><p>微软主流 TTS 引擎，无需 API Key，免费使用。</p><p><strong>推荐音色：</strong></p><table tabindex="0"><thead><tr><th>情感风格</th><th>推荐音色</th><th>说明</th></tr></thead><tbody><tr><td>治愈</td><td><code>zh-CN-Xiaoxiao</code></td><td>女声，温暖清晰</td></tr><tr><td>悬疑</td><td><code>zh-CN-Yunxi</code></td><td>男声，低沉留白</td></tr><tr><td>励志</td><td><code>zh-CN-Yunyang</code></td><td>男声，专业有力</td></tr><tr><td>浪漫</td><td><code>zh-CN-Xiaoyi</code></td><td>女声，细腻柔和</td></tr><tr><td>怀旧</td><td><code>zh-CN-Xiaoxiao</code></td><td>女声，柔和温暖</td></tr></tbody></table><h3 id="f5-tts-音色克隆-可选" tabindex="-1">F5-TTS 音色克隆（可选） <a class="header-anchor" href="#f5-tts-音色克隆-可选" aria-label="Permalink to &quot;F5-TTS 音色克隆（可选）&quot;">​</a></h3><p>只需 15–30 秒参考音频，即可克隆任意音色：</p><ol><li>准备参考音频（MP3/WAV，15–30 秒，说话清晰）</li><li>设置 → 配音配置 → F5-TTS → 上传参考音频</li><li>选择克隆音色作为配音</li></ol><blockquote><p>⚠️ F5-TTS 需要独立安装，详见<a href="./installation.html#f5-tts-音色克隆">安装指南</a>。</p></blockquote><h3 id="语速与音调" tabindex="-1">语速与音调 <a class="header-anchor" href="#语速与音调" aria-label="Permalink to &quot;语速与音调&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>范围</th><th>默认</th><th>说明</th></tr></thead><tbody><tr><td>语速</td><td>0.6x – 1.5x</td><td>1.0x</td><td>低于 1.0 放慢，高于 1.0 加快</td></tr><tr><td>音调</td><td>-50% – +50%</td><td>0</td><td>负值降低音调，正值提高</td></tr></tbody></table><hr><h2 id="step-4-—-字幕对齐" tabindex="-1">Step 4 — 字幕对齐 <a class="header-anchor" href="#step-4-—-字幕对齐" aria-label="Permalink to &quot;Step 4 — 字幕对齐&quot;">​</a></h2><h3 id="tts-word-level-timing" tabindex="-1">TTS Word-level Timing <a class="header-anchor" href="#tts-word-level-timing" aria-label="Permalink to &quot;TTS Word-level Timing&quot;">​</a></h3><p>Edge-TTS 提供逐词时间戳（word-level timing），精确到每个字的起止时间，Narrafiilm 将其用于 ASS 字幕生成。</p><h3 id="字幕样式" tabindex="-1">字幕样式 <a class="header-anchor" href="#字幕样式" aria-label="Permalink to &quot;字幕样式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>样式</th><th>效果</th></tr></thead><tbody><tr><td><strong>电影黑底白字</strong>（默认）</td><td>底部居中，黑底白字，带淡淡描边</td></tr><tr><td><strong>透明覆盖</strong></td><td>底部居中，无背景，文字描边</td></tr><tr><td><strong>卡片式</strong></td><td>全宽底栏，半透明背景</td></tr><tr><td><strong>顶部字幕</strong></td><td>用于说明画面外事件</td></tr></tbody></table><h3 id="ass-高级参数" tabindex="-1">ASS 高级参数 <a class="header-anchor" href="#ass-高级参数" aria-label="Permalink to &quot;ASS 高级参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>可选值</th><th>默认</th></tr></thead><tbody><tr><td>字体大小</td><td>48–96 pt</td><td>60 pt</td></tr><tr><td>行数上限</td><td>1–3 行</td><td>1 行</td></tr><tr><td>描边宽度</td><td>0–5 pt</td><td>2 pt</td></tr></tbody></table><hr><h2 id="step-5-—-视频合成" tabindex="-1">Step 5 — 视频合成 <a class="header-anchor" href="#step-5-—-视频合成" aria-label="Permalink to &quot;Step 5 — 视频合成&quot;">​</a></h2><h3 id="ffmpeg-管线" tabindex="-1">FFmpeg 管线 <a class="header-anchor" href="#ffmpeg-管线" aria-label="Permalink to &quot;FFmpeg 管线&quot;">​</a></h3><p>配音、字幕、原片通过 FFmpeg 合并：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 简化逻辑</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> narration.wav</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ass=subtitle.ass&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\\\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aac</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.mp4</span></span></code></pre></div><h3 id="编码选择" tabindex="-1">编码选择 <a class="header-anchor" href="#编码选择" aria-label="Permalink to &quot;编码选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th>编码</th><th>兼容性</th><th>体积</th><th>推荐场景</th></tr></thead><tbody><tr><td><strong>H.264</strong></td><td>所有设备</td><td>中</td><td>通用输出，微信/B站直接上传</td></tr><tr><td><strong>H.265</strong></td><td>iOS 15+/Android 10+</td><td>小约 40%</td><td>存档，高质量输出</td></tr></tbody></table><h3 id="音频混合" tabindex="-1">音频混合 <a class="header-anchor" href="#音频混合" aria-label="Permalink to &quot;音频混合&quot;">​</a></h3><p>Narrafiilm 支持将原片音频保留为背景音（可选），配音音量自动降低原音：</p><table tabindex="0"><thead><tr><th>模式</th><th>说明</th></tr></thead><tbody><tr><td>仅配音（默认）</td><td>完全替换为 AI 旁白</td></tr><tr><td>配音+原音</td><td>背景音乐/环境音保留，配音覆盖人声</td></tr><tr><td>静音</td><td>仅保留画面，导出纯视频</td></tr></tbody></table><hr><h2 id="输出与导出" tabindex="-1">输出与导出 <a class="header-anchor" href="#输出与导出" aria-label="Permalink to &quot;输出与导出&quot;">​</a></h2><h3 id="mp4-直接输出" tabindex="-1">MP4（直接输出） <a class="header-anchor" href="#mp4-直接输出" aria-label="Permalink to &quot;MP4（直接输出）&quot;">​</a></h3><p>成品视频文件，可直接用于各平台发布。</p><h3 id="剪映草稿-json" tabindex="-1">剪映草稿 JSON <a class="header-anchor" href="#剪映草稿-json" aria-label="Permalink to &quot;剪映草稿 JSON&quot;">​</a></h3><p>导出 <code>.draft.json</code> 原生剪映格式，导入剪映后保留：</p><ul><li>时间轴和分割点</li><li>字幕轨道（可继续编辑）</li><li>配音轨道</li></ul><h3 id="单独导出" tabindex="-1">单独导出 <a class="header-anchor" href="#单独导出" aria-label="Permalink to &quot;单独导出&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件</th><th>格式</th><th>说明</th></tr></thead><tbody><tr><td>配音音频</td><td>MP3 / WAV</td><td>可单独用于播客等</td></tr><tr><td>字幕</td><td>ASS / SRT</td><td>ASS 含样式，SRT 通用</td></tr><tr><td>解说稿</td><td>TXT</td><td>原始文案</td></tr></tbody></table><hr><h2 id="质量优化技巧" tabindex="-1">质量优化技巧 <a class="header-anchor" href="#质量优化技巧" aria-label="Permalink to &quot;质量优化技巧&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>解决方案</th></tr></thead><tbody><tr><td>解说稿不够自然</td><td>切换情感风格或调整解说长度</td></tr><tr><td>音画不同步</td><td>检查视频帧率是否正常，降低抽帧间隔</td></tr><tr><td>字幕时间轴不准</td><td>使用 Edge-TTS（非 F5-TTS），确认 TTS word-level timing 可用</td></tr><tr><td>视频体积过大</td><td>切换 H.265 编码或降低分辨率</td></tr><tr><td>配音机械感</td><td>切换至 F5-TTS 克隆音色，或尝试其他 Edge-TTS 音色</td></tr></tbody></table><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./quick-start.html">快速开始</a> — 5 分钟上手</li><li><a href="./../features.html">功能介绍</a> — 功能总览</li><li><a href="./exporting.html">导出格式</a> — 详细导出参数</li></ul>`,71)])])}const u=a(n,[["render",i]]);export{b as __pageData,u as default};
